const kb = $input.first().json;
if (!kb || !kb[0]) {
  return [{ json: { knowledge: 'No knowledge base found for this client.' } }];
}

const data = kb[0];
const sections = [];

if (data.business_description) {
  sections.push(`## About the Business\n${data.business_description}`);
}

if (data.services && data.services.length > 0) {
  sections.push(`## Services\n${data.services.map(s => `- ${s}`).join('\n')}`);
}

if (data.business_hours) {
  sections.push(`## Business Hours\n${data.business_hours}`);
}

if (data.contact_info) {
  const c = data.contact_info;
  const parts = [];
  if (c.phone) parts.push(`Phone: ${c.phone}`);
  if (c.email) parts.push(`Email: ${c.email}`);
  if (c.address) parts.push(`Address: ${c.address}`);
  if (parts.length > 0) sections.push(`## Contact\n${parts.join('\n')}`);
}

if (data.faq && data.faq.length > 0) {
  const faqText = data.faq.map(f => `Q: ${f.question}\nA: ${f.answer}`).join('\n\n');
  sections.push(`## FAQ\n${faqText}`);
}

if (data.brand_voice) {
  sections.push(`## Brand Voice\n${data.brand_voice}`);
}

if (data.social_profiles && Object.keys(data.social_profiles).length > 0) {
  const profiles = Object.entries(data.social_profiles).map(([k, v]) => `- ${k}: ${v}`).join('\n');
  sections.push(`## Social Profiles\n${profiles}`);
}

if (data.review_sources && data.review_sources.length > 0) {
  const reviews = data.review_sources.map(r => `- ${r.platform}: ${r.url}${r.rating ? ` (${r.rating}/5, ${r.count} reviews)` : ''}`).join('\n');
  sections.push(`## Reviews\n${reviews}`);
}

if (data.team_members && data.team_members.length > 0) {
  const team = data.team_members.map(m => `- ${m.name}${m.role ? ` — ${m.role}` : ''}`).join('\n');
  sections.push(`## Team\n${team}`);
}

if (data.icp_criteria && data.icp_criteria.notes) {
  sections.push(`## Ideal Customer Profile\n${data.icp_criteria.notes}`);
}

if (data.company_culture) {
  sections.push(`## Company Culture\n${data.company_culture}`);
}

if (data.industry_keywords && data.industry_keywords.length > 0) {
  sections.push(`## Industry Keywords\n${data.industry_keywords.join(', ')}`);
}

return [{ json: {
  knowledge: sections.join('\n\n'),
  raw: data
}}];
